<template>
  <div id="nav">
    <div class="nav-top">
      <div class="nav-nav">
        <ul :class="'list' + animation">
          <li>
            <router-link to="/">首页</router-link>
          </li>
          <li>
            <router-link to="/blog/0">博客</router-link>
          </li>
          <li>
            <router-link to="/diary">时间轴</router-link>
          </li>
          <li>
            <router-link to="/message">留言</router-link>
          </li>
          <li>
            <router-link to="/links">友链</router-link>
          </li>
          <li>
            <router-link to="/about">关于</router-link>
          </li>
        </ul>
      </div>
      <el-popover
          v-if="$store.state.userIf"
          placement="bottom"
          width="170"
          trigger="hover"
      >
<!--        显示用户名-->
        <p>欢迎登陆：{{login.userData.user}}</p><br>
<!--        修改头像-->
        <el-button type="primary" plain size="mini" @click="photo.ifDialog = true">修改头像</el-button>
        <br><br>
<!--        修改头像的弹出层-->
<!--        -->
        <el-dialog title="修改头像"
                   :visible.sync="photo.ifDialog"
                   center width="35%"
                   :modal-append-to-body="false"
                   :close-on-click-modal="false"
        >
<!--         http://localhost:3000 -->
          <el-upload
              class="avatar-uploader"
              action="https://api-potatochunks.vercel.app/upload"
              drag
              :multiple="false"
              :show-file-list="false"
              :on-success="handleAvatarSuccess"
              :before-upload="beforeAvatarUpload"
              :with-credentials="true"
          >
            <img v-if="photo.img" :src="photo.img" class="avatar">
            <i v-else class="el-icon-plus avatar-uploader-icon"></i>
          </el-upload>
        </el-dialog>
<!--        -->
<!--        -->
<!--        退出登录-->
<!--        -->
<!--        -->
        <el-button type="danger" plain size="mini" @click="loginOut">退出登录</el-button>
        <div class="userImg" slot="reference" v-if="$store.state.userIf">
          <el-avatar :src="login.userData.photo"></el-avatar>
        </div>
      </el-popover>
<!--      -->
<!--      -->
<!--      登录注册-->
      <div class="nav-login" v-else >
        <el-button type="primary" size="min" @click="login.dialogFormVisible = true">登录</el-button>
        <el-button type="success" @click="openRegister" >注册</el-button>
<!--        -->
<!--        注册-->
        <el-dialog title="注册" :visible.sync="register.dialogFormVisible" center width="35%" :modal-append-to-body="false"  @close="closeRegister" :close-on-click-modal="false">
          <el-form :model="form" :rules="rules" ref="form">
            <el-form-item label="用户名" prop="user">
              <el-input v-model="form.user"></el-input>
            </el-form-item>
            <el-form-item label="密码" prop="pwd">
              <el-input v-model="form.pwd" show-password></el-input>
            </el-form-item>
            <el-form-item label="验证码" prop="code" class="code">
              <el-input v-model="form.code"></el-input>
              <el-link class="svg" v-html="code.codeText" @click="getNewCode" :disabled="code.ifCode" :underline="false" :title="code.title"></el-link>
            </el-form-item>
          </el-form>
          <div slot="footer" class="dialog-footer">
            <el-button @click="closeRegister">取 消</el-button>
            <el-button type="success" @click="determineRegister" :disabled="register.ifRegisterDisabled">注 册</el-button>
          </div>
        </el-dialog>
<!--        -->
<!--        登录-->
        <el-dialog title="登录" :visible.sync="login.dialogFormVisible" center width="35%" :modal-append-to-body="false"  @close="closeLogin" :close-on-click-modal="false">
          <el-form :model="login.form">
            <el-form-item label="用户名" prop="user">
              <el-input v-model="login.form.user"></el-input>
            </el-form-item>
            <el-form-item label="密码" prop="pwd">
              <el-input v-model="login.form.pwd" show-password></el-input>
            </el-form-item>
          </el-form>
          <div slot="footer" class="dialog-footer">
            <el-button @click="closeLogin">取 消</el-button>
            <el-button type="primary" @click="determineLogin" :disabled="login.ifLoginDisabled">登 录</el-button>
          </div>
        </el-dialog>
<!--        -->
<!--        -->
      </div>
    </div>
  </div>
</template>

<script>
  import path from "../router/path";
  //axios请求
  import axiosApi from "../api";
  let getCode = axiosApi.getCode,//获取验证码
      getCheckCode = axiosApi.getCheckCode,//验证验证码
      upRegister = axiosApi.upRegister,//注册
      Login = axiosApi.Login,//登录
      ifLogin = axiosApi.ifLogin,//判断是否登录
      loginOut = axiosApi.loginOut;//退出登录


  export default {
    name: "Nav",
    data(){
      return{
        form:{
          user:'',
          pwd:'',
          code:''
        },
        //注册验证
        rules:{
          //用户名验证
          user : [
            { required: true, message: '请输入用户名', trigger: 'blur' },
            {
              //数据类型
              type:"string",
              //正则规则
              pattern: /^[\w\u4e00-\u9fa5\uac00-\ud7ff\u0800-\u4e00\-]{2,7}$/,
              message: '2-7位，数字 字母 _ - 中日韩文',
              trigger: ['blur','change']
            }
          ],
          //密码验证
          pwd : [
            { required: true, message: '请输入密码', trigger: 'blur' },
            { type:"string", pattern:/^[0-9a-zA-Z]{6,18}$/, message: '6-18位，不允许出现奇怪的字符', trigger: ['blur','change']}
          ],

          code : {
            //验证验证码
            validator : (rule,value,cb)=>{
              if (!value){
                cb(new Error("请输入验证码!!"));
              }else{
                getCheckCode(value).then(res=>{
                  if (res.data.code === 0){
                    cb();
                  }else{
                    cb(new Error("验证码错误!!"));
                  }
                }).catch(e=>{
                  cb(new Error("(⊙o⊙)未知错误…"));
                });
              }
            },
            required: true,
            trigger: 'blur'
          }
        },
        code:{
          title:"验证码",
          ifCode:false,
          codeText:"加载中..."
        },
        //注册
        register:{
          //注册弹框显示
          dialogFormVisible : false,
          //注册按钮的状态
          ifRegisterDisabled : false
        },
        //登录
        login:{
          //登录弹框显示
          dialogFormVisible : false,
          //form
          form:{
            user:'',
            pwd:'',
          },
          //登录按钮的状态
          ifLoginDisabled : false,
          //用户数据
          userData: {},
        },
        //修改头像
        //
        photo:{
          ifDialog:false,
          img:""
        }
      }
    },
    components:{
      //
    }
    ,computed:{
      //Nav下面的条条
      animation(){
        let arrList;
        arrList = path.map(item=>item.name);
        let index = arrList.indexOf(this.$route.name);
        if(this.$route.name === "Article") index = 1;
        return index + 1
      }
    }
    ,methods:{
      //注册
      closeRegister(){
        //关闭注册
        this.register.dialogFormVisible = false;
        this.form.user = this.form.pwd = "";
      },
      //打开注册
      openRegister(){
        this.register.dialogFormVisible = true;
        this.form.user = this.form.pwd = this.form.code = '';
        this.getNewCode();
      },
      //确定注册
      determineRegister(){
        //
        this.register.ifRegisterDisabled = true;
        this.$refs["form"].validate((valid) => {
            if (valid) {//验证表单
              //注册
              upRegister(this.form)
                .then(d=>{
                  //成功
                  this.register.ifRegisterDisabled = false;
                  if (d.data.code === 0) {
                    this.$message({
                      message: '恭喜你，注册成功',
                      type: 'success'
                    });
                    // window.location.reload();
                    this.register.dialogFormVisible = false;
                    this.login.dialogFormVisible = true;
                    this.form.user = this.form.pwd = this.form.code = '';
                    this.login.form.user = this.login.form.pwd = '';
                    this.r
                  }else{
                    this.$message.error(d.data.msg)
                  }
                })
                .catch(e=>{
                  //失败
                  this.$message.error("出现不明原因错误")
                })
              //
            } else {
              this.register.ifRegisterDisabled = false;
              //验证没通过
              return false;
            }
          });
      },
      //验证码请求
      getNewCode(){
        this.form.code = "";
        if(!this.code.ifCode){
          this.code.ifCode = true;
          getCode().then(res=>{
            this.code.codeText = res.data.data;
            this.code.title = res.data.msg;
          });
          setTimeout(()=>{
            this.code.ifCode = false;
            this.code.title = "验证码";
          },3000)
        }

      },
      //
      //登录
      //关闭登录
      closeLogin(){
        this.login.dialogFormVisible = false;
        this.login.form.user = this.login.form.pwd = "";
      },
      //确定登录
      determineLogin(){
        //按钮状态
        this.login.ifLoginDisabled = true;
        Login(this.login.form)//登录请求
          .then(req=>{
            if (!req.data.code) {//判断登录是否成功
              this.login.form.user = this.login.form.pwd = '';
              this.$message({
                message: '恭喜你，登陆成功',
                type: 'success'
              });
              sessionStorage.setItem('userData',JSON.stringify(req.data.data));
              this.login.dialogFormVisible = false;//关闭登录框
              this.$store.commit('upUserIf',true);//更改登录状态
              this.login.form.user = this.login.form.pwd = '';
              this.form.user = this.form.pwd = this.form.code = '';
              //window.location.reload();
            }else{
              this.$message.error(req.data.msg);
              this.login.ifLoginDisabled = false;
            }
          })
          .catch(e=>{
            this.login.ifLoginDisabled = false;
          })
      },

      //退出登录
      loginOut(){
        sessionStorage.clear();
        loginOut();
        this.login.ifLoginDisabled = false;//开启登录按钮
        this.$store.commit('upUserIf',false);//更改登录状态退出登录
      },

      //更改头像
      handleAvatarSuccess(res, file) {
        this.photo.img = URL.createObjectURL(file.raw);
        this.photo.ifDialog = false;
        window.location.reload();
      },
      beforeAvatarUpload(file) {
        const ifImgType = /^(image\/jpeg|image\/png|image\/gif)$/.test(file.type);
        const isLt1M = file.size / 1024 / 1024 < 1;

        if (!ifImgType) {
          this.$message.error('上传头像图片只能是JPG 或png 或gif 格式!')
        }
        if (!isLt1M) {
          this.$message.error('上传头像图片大小不能超过 1MB!');
        }
        return ifImgType && isLt1M;
      }
    },
    mounted() {
      //刷新页面的时候请求一次
      this.getNewCode();
      //判断是否登录
      let userData = sessionStorage.userData;
      if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
      }
      try {
          userData = JSON.parse(userData)
      }catch (e) {
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
      }
      if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
      }
      this.$store.commit('upUserIf',true);
      this.login.userData = userData
    }
  }
</script>

<style scoped lang="less">
  #nav{
    overflow: hidden;
    position: fixed;
    top: 0;
    left: 0;
    min-width: 100%;
    max-width: 1080px;
    height: 60px;
    background-color: #fff;
    border-bottom: 1px solid #e8e9e7;
    z-index: 10;
    >.nav-top{
      display: flex;
      justify-content: space-between;
      box-sizing: border-box;
      max-width: 1260px;
      min-width: 1064px;
      height: 60px;
      padding: 0 50px;
      margin: 0 auto;
      >.nav-login{
        height: 60px;
        line-height: 60px;
        >.el-button{
          padding: 9px 13px;
        }
      }
      >.nav-nav{
        width: 840px;
        height: 60px;
        >ul{
          display: flex;
          width: 100%;
          height: 100%;
          >li{
            flex: 1;
            >a{
              position: relative;
              display: block;
              width: 100%;
              height: 100%;
              text-align: center;
              line-height: 60px;
              font-weight: 400;
              color: #212220;
              font-size: 15px;
              transition: color .3s;
              &::after{
                position: absolute;
                bottom: 0;
                left: 0;
                right: 0;
                margin: 0 auto;
                content: "";
                width: 0;
                height: 2px;
                background-color: #CD3D35;
                transition: width .3s;
              }
              &:hover{
                color: #A19ECC;
                /*&::after{*/
                /*  width: 100%;*/
                /*}*/
              }
            }
          }
          &.list1 li:nth-child(1),
          &.list2 li:nth-child(2),
          &.list3 li:nth-child(3),
          &.list4 li:nth-child(4),
          &.list5 li:nth-child(5),
          &.list6 li:nth-child(6){
            >a{
              color: #A19ECC;
              &::after{
                width: 100%;
              }
            }
          }
        }
      }
      span{
        display: flex;
        align-items: center;
        cursor: pointer;
        .userImg{
          span{
            border: 1px solid #000;
          }
        }
      }
    }
  }
  .code{
    .el-input{
      float: left;
      width: 35%;
    }
    a.svg{
      display: block;
      float: left;
      width: 35%;
      height: 40px;
      /deep/ svg{
        width: 100% !important;
        height: 100% !important;
      }
    }
  }
  .avatar-uploader{
    display: flex;
    justify-content: center;
  }
  .avatar-uploader .el-upload {
    border: 1px dashed #d9d9d9;
    border-radius: 6px;
    cursor: pointer;
    position: relative;
    overflow: hidden;
  }
  .avatar-uploader .el-upload:hover {
    border-color: #409EFF;
  }
  .avatar-uploader-icon {
    font-size: 28px;
    color: #8c939d;
    width: 100%;
    height: 100%;
    line-height: 178px;
    text-align: center;
  }
  .avatar {
    width: 178px;
    height: 178px;
    display: block;
  }
  .el-upload-dragger{
    /*display: flex;*/
    /*justify-content: center;*/
    /*flex-wrap: wrap;*/
    img{
      display: inline;
    }
  }
  .el-popover{
    p{
      text-align: center;
    }
    .el-button{
      margin: 0 40px;
    }
  }
</style>