import axios from "axios";
//配置默认的参数
//http://www.dbclick.xn--ses554g
axios.defaults.baseURL = 'https://api-potatochunks.vercel.app/blog/';//默认访问地址
axios.defaults.withCredentials = true;//跨域允许携带cookie
axios.defaults.headers.post["Content-Type"] = "application/x-www-from-urlencoded";//设置post请求格式

export default {
  //标签info
  getArticleInfo(){
    return axios.post("/article/getInfo")
  },
  //获取热门文章
  getArticlePopular(limit=8){
    //limit代表获取的文章数量默认是8篇
    return axios.post("/article/getPopular",{limit});
  },
  //获取最新文章
  getArticleNew:(function(){
    let skip = 0 ,limit = 5;
    //skip从0篇开始 limit到第五篇
    //接受tag文章的标签分类 ifNew是否是新的
    return function(tag="",ifNew = false){
      if(ifNew){
        skip = 0;
        limit = 5;
      }
      let data = {skip,limit,tag};
      skip += limit;
      return axios.post("/article/getArticleNew",data)
    }
  })(),
  //获取文章内容
  //文章的id
  getArticle(options){
    return axios.post('/article',options)
  },
  //搜索框
  //要搜索的内容
  getSearch(options){
    return axios.post('/article/getSearch',options)
  },


  //获取验证码图片
  getCode(){
    return axios.post("/register/code");
  },
  //验证验证码
  //验证码
  getCheckCode(value){
    return axios.post("/register/checkCode",{value})
  },

  //注册
  //用户名 ,密码 ,验证码
  upRegister(form){
    return axios.post("/register/userPush",form)
  },


  //登录账户
  //用户名 ,密码
  Login(option){
    return axios.post("/login",option)
  },
  //判断用户是否登录
  ifLogin(){
    return axios.post("/login/ifLogin")
  },

  //退出登录
  loginOut(){
    return axios.post("/login/logout")
  },

  //注册友链
  //名称 ,网址 ,描述(不必须) ,验证码
  upLinks(option){
    return axios.post("/links/upLink",option);
  },

  //获取友链
  getLinks(){
    return axios.post("/links/getLink");
  },

  //提交评论
  //option = user ,content
  //用户名 ,内容
  createRegister(option){
    return axios.post('/message/createRegister',option)
  },
  //获取评论列表
  getMessage(){
    return axios.post("/message/getMessage")
  },
  //提交子留言
  //option = parentId ,user ,content ,fUser
  //评论的id 用户名 ,内容 ,评论对象
  createChild(option){
    return axios.post('/message/createChild',option)
  },

  //获取最近访客列表
  getVisitor(){
    return axios.post('/visitor')
  },

  //时间轴
  getDiaryList(){
    return axios.post('/diary/getDiaryList')
  }
};